#!/usr/bin/env node
/**
 * Direct REST upload of all 208 Directory CMS items to Webflow.
 * Bypasses the LLM-mediated MCP (which can't reliably ship 50KB+ JSON
 * through tool parameters without corruption).
 *
 * Setup (one-time, ~3 minutes):
 *   1. Webflow Dashboard → Workspace Settings → Integrations → API Access → Generate API Token
 *      Scopes needed: CMS read + write
 *   2. export WEBFLOW_API_TOKEN="paste_token_here"
 *   3. node scripts/import-to-webflow.mjs
 *
 * What it does:
 *   - Reads webflow/import-payload.json (already generated by build-payload.mjs)
 *   - POSTs all 208 items to Webflow's bulk-create endpoint, in batches of 100
 *   - Captures the returned item IDs into webflow/live-items.json
 *   - Items are created as DRAFTS — review in Webflow CMS, then publish
 *
 * Optional flags:
 *   --dry-run        Print what it would do, don't call the API
 *   --publish        Also publish items after creation
 */

import fs from 'node:fs';
import path from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const root = path.resolve(__dirname, '..');

const TOKEN = process.env.WEBFLOW_API_TOKEN;
const COLLECTION_ID = '69ec1ea64d23f0cbe5590856';
const SITE_ID = '65003933b9af86bc33bf4488';
const API_BASE = 'https://api.webflow.com/v2';

const DRY_RUN = process.argv.includes('--dry-run');
const PUBLISH = process.argv.includes('--publish');

if (!TOKEN && !DRY_RUN) {
  console.error('\nMissing WEBFLOW_API_TOKEN environment variable.');
  console.error('Get a token at https://webflow.com/dashboard/sites/<your-site>/integrations');
  console.error('Then: export WEBFLOW_API_TOKEN="..." && node scripts/import-to-webflow.mjs\n');
  process.exit(1);
}

const payload = JSON.parse(fs.readFileSync(path.join(root, 'webflow', 'import-payload.json'), 'utf-8'));
const allItems = payload.batches.flatMap(b => b.items);
console.log(`Loaded ${allItems.length} items from import-payload.json`);
console.log(`Mode: ${DRY_RUN ? 'DRY RUN (no API calls)' : 'LIVE'}, publish: ${PUBLISH}`);

async function api(method, urlPath, body) {
  if (DRY_RUN) {
    console.log(`[dry] ${method} ${urlPath} ${body ? `(${JSON.stringify(body).length} bytes)` : ''}`);
    return { items: (body?.items || []).map((it, i) => ({ id: `dry-${Date.now()}-${i}`, fieldData: { slug: it.fieldData?.slug, name: it.fieldData?.name } })) };
  }
  const r = await fetch(`${API_BASE}${urlPath}`, {
    method,
    headers: {
      'Authorization': `Bearer ${TOKEN}`,
      'Content-Type': 'application/json',
      'accept-version': '2.0.0'
    },
    body: body ? JSON.stringify(body) : undefined
  });
  if (!r.ok) {
    const errText = await r.text();
    throw new Error(`${method} ${urlPath} → ${r.status} ${r.statusText}\n${errText.slice(0, 1000)}`);
  }
  return r.json();
}

const live = [];
const BATCH_SIZE = 100; // Webflow API limit

for (let i = 0; i < allItems.length; i += BATCH_SIZE) {
  const slice = allItems.slice(i, i + BATCH_SIZE);
  const items = slice.map(fd => ({ fieldData: fd, isDraft: true }));
  console.log(`Batch ${i / BATCH_SIZE + 1}: creating ${items.length} items (offset ${i})...`);
  let attempt = 0;
  let created;
  while (attempt < 3) {
    attempt++;
    try {
      created = await api('POST', `/collections/${COLLECTION_ID}/items`, { items });
      break;
    } catch (err) {
      console.error(`  attempt ${attempt} failed: ${err.message}`);
      if (attempt >= 3) throw err;
      await new Promise(r => setTimeout(r, 2000 * attempt));
    }
  }
  for (const item of (created.items || [])) {
    live.push({
      id: item.id,
      fieldData: { slug: item.fieldData?.slug, name: item.fieldData?.name }
    });
  }
  console.log(`  → created ${created.items?.length || 0}, total live: ${live.length}`);
  // Persist after each batch
  fs.writeFileSync(path.join(root, 'webflow', 'live-items.json'), JSON.stringify({ items: live }, null, 2));
}

console.log(`\nWrote ${live.length} items to webflow/live-items.json`);

if (PUBLISH && !DRY_RUN) {
  console.log(`\nPublishing ${live.length} items...`);
  const ids = live.map(i => i.id);
  for (let i = 0; i < ids.length; i += BATCH_SIZE) {
    const slice = ids.slice(i, i + BATCH_SIZE);
    await api('POST', `/collections/${COLLECTION_ID}/items/publish`, { itemIds: slice });
    console.log(`  published batch ${i / BATCH_SIZE + 1}: ${slice.length} items`);
  }
}

console.log('\nDone.');
